import { Controller, Get, Param, Query } from '@nestjs/common';
import { ApiOperation, ApiParam, ApiResponse, ApiTags } from '@nestjs/swagger';

import { MetricsService } from '@modules/metrics/metrics.service';
import { RelatedProductsService } from '@modules/rest/related-products/related-products.service';

import { dailyTrackingKeys } from '@constants/common.constant';

import { LogExecution } from '@decorators/log-execution.decorator';

import { BrandProductsQueryDto } from '@dto/brand-products/brand-products-query.dto';
import { BrandProductsResponseDto } from '@dto/brand-products/brand-products-response.dto';
import { RelatedProductsQueryDto } from '@dto/related-products/related-products-query.dto';
import { RelatedProductsResponseDto } from '@dto/related-products/related-products-response.dto';

@ApiTags('Related Products')
@Controller('related-products')
export class RelatedProductsController {
	constructor(
		private readonly relatedProductsService: RelatedProductsService,
		private readonly metricsService: MetricsService,
	) {}

	@Get('brand')
	@ApiOperation({ summary: 'Get products for a specific brand' })
	@ApiResponse({
		status: 200,
		description: 'Returns products for the specified brand',
		type: BrandProductsResponseDto,
	})
	@ApiResponse({ status: 404, description: 'Brand not found' })
	@ApiResponse({ status: 500, description: 'Internal server error' })
	async getBrandProducts(
		@Query() query: BrandProductsQueryDto,
	): Promise<BrandProductsResponseDto> {
		return await this.relatedProductsService.getBrandProducts(query);
	}

	@Get(':productId')
	@ApiOperation({ summary: 'Get related products for a specific product ID' })
	@ApiParam({ name: 'productId', type: String, description: 'Product ID' })
	@ApiResponse({
		status: 200,
		description: 'Returns related products for the specified product ID',
		type: RelatedProductsResponseDto,
	})
	@ApiResponse({ status: 404, description: 'Product not found' })
	@ApiResponse({ status: 500, description: 'Internal server error' })
	@LogExecution({
		paramFormatter: (params: [string, RelatedProductsQueryDto]) => ({
			productId: params[0],
			query: params[1],
		}),
		responseFormatter: (response: RelatedProductsResponseDto) => ({
			relatedProducts: response.related_products.length,
			productId: response.product_id,
			mmsFallback: response.mms_fallback,
			colorId: response.color_id,
		}),
	})
	async getRelatedProducts(
		@Param('productId') productId: string,
		@Query() query: RelatedProductsQueryDto,
	): Promise<RelatedProductsResponseDto> {
		await this.metricsService.incrementDailyCounter(
			dailyTrackingKeys.RELATED_PRODUCTS_REQUESTS,
		);
		return this.relatedProductsService.getRelatedProducts(productId, query);
	}
}
```

