	@IsInt({ message: 'Limit must be an integer' })
	@Min(1, { message: 'Limit must be between 1 and 30' })
	@Max(30, { message: 'Limit must be between 1 and 30' })
	@Type(() => Number)
	limit?: number = 30;

	@ApiProperty({
		description: 'Color ID to filter related products',
		required: false,
	})
	@IsOptional()
	@IsInt({ message: 'ColorId must be an integer' })
	@Type(() => Number)
	colorId?: number;
}
